<body>
  <main class="app">
    <section class="panel hud" aria-label="Game status">
      <div class="title-block">
        <h1>Snake</h1>
        <p class="subtitle">Use the arrow keys to eat food, grow longer, and avoid the walls or your own tail.</p>
      </div>
      <div class="stats">
        <div class="pill">
          <span class="pill-label">Score</span>
          <span class="pill-value" id="score">0</span>
        </div>
        <div class="pill">
          <span class="pill-label">Best</span>
          <span class="pill-value" id="best-score">0</span>
        </div>
      </div>
    </section>

    <section class="panel game-shell">
      <div class="board-frame">
        <canvas id="game" aria-label="Snake game board" role="img"></canvas>
        <div class="overlay" id="overlay">
          <div class="overlay-card">
            <h2 id="overlay-title">Ready?</h2>
            <p id="overlay-message">Press any arrow key to start. Keep moving and collect the pink food.</p>
            <div class="actions">
              <button class="primary" id="restart-button" type="button">Start Game</button>
            </div>
          </div>
        </div>
      </div>
    </section>

    <section class="panel footer">
      <span class="hint-keys" aria-label="Control keys">
        <span class="key">↑</span>
        <span class="key">↓</span>
        <span class="key">←</span>
        <span class="key">→</span>
      </span>
      <span>Press <strong>R</strong> to restart after game over.</span>
    </section>
  </main>

  <script>
    const canvas = document.getElementById("game");
    const context = canvas.getContext("2d");
    const scoreEl = document.getElementById("score");
    const bestScoreEl = document.getElementById("best-score");
    const overlay = document.getElementById("overlay");
    const overlayTitle = document.getElementById("overlay-title");
    const overlayMessage = document.getElementById("overlay-message");
    const restartButton = document.getElementById("restart-button");

    const gridSize = 20;
    const tickLengthMs = 140;
    const keyDirectionMap = {
      ArrowUp: { x: 0, y: -1 },
      ArrowDown: { x: 0, y: 1 },
      ArrowLeft: { x: -1, y: 0 },
      ArrowRight: { x: 1, y: 0 }
    };

    const state = {
      snake: [],
      direction: { x: 1, y: 0 },
      queuedDirection: { x: 1, y: 0 },
      food: { x: 0, y: 0 },
      score: 0,
      bestScore: Number(localStorage.getItem("snake-best-score") || 0),
      running: false,
      gameOver: false,
      hasStarted: false,
      lastTick: 0
    };

    bestScoreEl.textContent = String(state.bestScore);

    function resizeCanvas() {
      const frame = canvas.parentElement;
      const dpr = Math.max(1, window.devicePixelRatio || 1);
      const size = Math.max(280, Math.floor(frame.clientWidth));
      canvas.width = size * dpr;
      canvas.height = size * dpr;
      context.setTransform(1, 0, 0, 1, 0, 0);
      context.scale(dpr, dpr);
      draw();
    }

    function randomOpenCell() {
      const occupied = new Set(state.snake.map((segment) => `${segment.x},${segment.y}`));
      const openCells = [];

      for (let y = 0; y < gridSize; y += 1) {
        for (let x = 0; x < gridSize; x += 1) {
          const key = `${x},${y}`;
          if (!occupied.has(key)) {
            openCells.push({ x, y });
          }
        }
      }

      return openCells[Math.floor(Math.random() * openCells.length)];
    }

    function placeFood() {
      state.food = randomOpenCell();
    }

    function resetGame() {
      const middle = Math.floor(gridSize / 2);
      state.snake = [
        { x: middle - 1, y: middle },
        { x: middle - 2, y: middle },
        { x: middle - 3, y: middle }
      ];
      state.direction = { x: 1, y: 0 };
      state.queuedDirection = { x: 1, y: 0 };
      state.score = 0;
      state.running = false;
      state.gameOver = false;
      state.hasStarted = false;
      state.lastTick = 0;
      scoreEl.textContent = "0";
      placeFood();
      showOverlay(
        "Ready?",
        "Press any arrow key to start. Keep moving and collect the pink food.",
        "Start Game"
      );
      draw();
    }

    function startGame() {
      if (!state.gameOver) {
        state.running = true;
        state.hasStarted = true;
        hideOverlay();
      }
    }

    function showOverlay(title, message, buttonLabel) {
      overlayTitle.textContent = title;
      overlayMessage.textContent = message;
      restartButton.textContent = buttonLabel;
      overlay.hidden = false;
    }

    function hideOverlay() {
      overlay.hidden = true;
    }

    function updateBestScore() {
      if (state.score > state.bestScore) {
        state.bestScore = state.score;
        localStorage.setItem("snake-best-score", String(state.bestScore));
        bestScoreEl.textContent = String(state.bestScore);
      }
    }

    function endGame() {
      state.running = false;
      state.gameOver = true;
      updateBestScore();
      showOverlay(
        "Game Over",
        `Final score: ${state.score}. Press R or use the button to play again.`,
        "Play Again"
      );
    }

    function queueDirection(nextDirection) {
      const current = state.direction;
      const isReverse =
        nextDirection.x === -current.x &&
        nextDirection.y === -current.y;

      if (isReverse) {
        return;
      }

      state.queuedDirection = nextDirection;
    }

    function handleKeyDown(event) {
      const nextDirection = keyDirectionMap[event.key];

      if (nextDirection) {
        event.preventDefault();
        if (state.gameOver) {
          resetGame();
        }
        queueDirection(nextDirection);
        startGame();
        return;
      }

      if (event.key.toLowerCase() === "r") {
        resetGame();
      }
    }

    function updateScore(nextScore) {
      state.score = nextScore;
      scoreEl.textContent = String(state.score);
    }

    function tick() {
      state.direction = state.queuedDirection;
      const head = state.snake[0];
      const nextHead = {
        x: head.x + state.direction.x,
        y: head.y + state.direction.y
      };

      const hitsWall =
        nextHead.x < 0 ||
        nextHead.x >= gridSize ||
        nextHead.y < 0 ||
        nextHead.y >= gridSize;

      const hitsSelf = state.snake.some(
        (segment) => segment.x === nextHead.x && segment.y === nextHead.y
      );

      if (hitsWall || hitsSelf) {
        endGame();
        return;
      }

      state.snake.unshift(nextHead);

      const ateFood =
        nextHead.x === state.food.x &&
        nextHead.y === state.food.y;

      if (ateFood) {
        updateScore(state.score + 1);
        placeFood();
      } else {
        state.snake.pop();
      }
    }

    function drawBoard(size, cellSize) {
      for (let y = 0; y < gridSize; y += 1) {
        for (let x = 0; x < gridSize; x += 1) {
          context.fillStyle = (x + y) % 2 === 0 ? "#10213a" : "#142844";
          context.fillRect(x * cellSize, y * cellSize, cellSize, cellSize);
        }
      }

      context.strokeStyle = "rgba(148, 163, 184, 0.06)";
      context.lineWidth = 1;
      for (let i = 0; i <= gridSize; i += 1) {
        const position = i * cellSize;
        context.beginPath();
        context.moveTo(position, 0);
        context.lineTo(position, size);
        context.stroke();
        context.beginPath();
        context.moveTo(0, position);
        context.lineTo(size, position);
        context.stroke();
      }
    }

    function drawSnake(cellSize) {
      state.snake.forEach((segment, index) => {
        const padding = index === 0 ? 2 : 3;
        const radius = index === 0 ? 7 : 6;
        context.fillStyle = index === 0 ? "#4ade80" : "#22c55e";
        roundRect(
          segment.x * cellSize + padding,
          segment.y * cellSize + padding,
          cellSize - padding * 2,
          cellSize - padding * 2,
          radius
        );
        context.fill();
      });
    }

    function drawFood(cellSize) {
      const padding = 4;
      context.fillStyle = "#fb7185";
      roundRect(
        state.food.x * cellSize + padding,
        state.food.y * cellSize + padding,
        cellSize - padding * 2,
        cellSize - padding * 2,
        8
      );
      context.fill();
    }

    function roundRect(x, y, width, height, radius) {
      context.beginPath();
      context.moveTo(x + radius, y);
      context.arcTo(x + width, y, x + width, y + height, radius);
      context.arcTo(x + width, y + height, x, y + height, radius);
      context.arcTo(x, y + height, x, y, radius);
      context.arcTo(x, y, x + width, y, radius);
      context.closePath();
    }

    function draw() {
      const size = canvas.clientWidth;
      const cellSize = size / gridSize;

      context.clearRect(0, 0, size, size);
      drawBoard(size, cellSize);
      drawFood(cellSize);
      drawSnake(cellSize);
    }

    function frame(timestamp) {
      if (!state.lastTick) {
        state.lastTick = timestamp;
      }

      const elapsed = timestamp - state.lastTick;

      if (state.running && elapsed >= tickLengthMs) {
        state.lastTick = timestamp;
        tick();
        draw();
      } else if (!state.running) {
        state.lastTick = timestamp;
      }

      requestAnimationFrame(frame);
    }

    restartButton.addEventListener("click", () => {
      resetGame();
      startGame();
    });

    window.addEventListener("keydown", handleKeyDown, { passive: false });
    window.addEventListener("resize", resizeCanvas);

    resetGame();
    resizeCanvas();
    requestAnimationFrame(frame);
  </script>
</body>
</html>
