        </div>
        <div class="pill">
          <span class="pill-label">Best</span>
          <span class="pill-value" id="best-score">0</span>
        </div>
      </div>
    </section>

    <section class="panel game-shell">
      <div class="board-frame">
        <canvas id="game" aria-label="Snake game board" role="img"></canvas>
        <div class="overlay" id="overlay">
          <div class="overlay-card">
            <h2 id="overlay-title">Ready?</h2>
            <p id="overlay-message">Press any arrow key to start. Keep moving and collect the pink food.</p>
            <div class="actions">
              <button class="primary" id="restart-button" type="button">Start Game</button>
            </div>
          </div>
        </div>
      </div>
    </section>

    <section class="panel footer">
      <span class="hint-keys" aria-label="Control keys">
        <span class="key">↑</span>
        <span class="key">↓</span>
        <span class="key">←</span>
        <span class="key">→</span>
      </span>
      <span>Press <strong>R</strong> to restart after game over.</span>
    </section>
